  final src = await ui.decodeImageFromCanvas(await _createCanvas(image));
  final List<ImageData> parts = [];
  final int partWidth = src.width ~/ 2;
  final int partHeight = src.height ~/ 2;
  for (int row = 0; row < 2; row++) {
    for (int col = 0; col < 2; col++) {
      int offsetX = col * partWidth;
      int offsetY = row * partHeight;
      final part = _createImageData(partWidth, partHeight);
      for (int x = 0; x < partWidth; x++) {
        for (int y = 0; y < partHeight; y++) {
          int pixelX = x + offsetX;
          int pixelY = y + offsetY;
          final pixel = src.getPixel(pixelX, pixelY);
          part.data.setPixel(x, y, pixel);
        }
      }
      parts.add(part);
    }
  }
  return parts;
}

Future<CanvasElement> _createCanvas(ImageElement image) async {
